using ICSharpCode.WpfDesign;namespace BgCommon.UI.Designer.VersionControl{    /// <summary>    /// 版本控制服务    /// </summary>    public class VersionControlService    {        private readonly VersionControlManager _versionControlManager;                /// <summary>        /// 版本控制管理器        /// </summary>        public VersionControlManager VersionControlManager => _versionControlManager;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public VersionControlService(DesignContext context)        {            _versionControlManager = new VersionControlManager(context);        }    }}